import React, { useEffect, useState } from 'react';
import Axios, { CancelToken } from 'axios';
import ReactMarkdown from "react-markdown";
import { Header, Segment, Container, Placeholder, Label, Divider } from 'semantic-ui-react';
import LazyLoad from 'react-lazyload';


function PageView({ page }) {

}

function NoteItem({ articlePath }) {
    const [article, setArticle] = useState(undefined);
    const source = CancelToken.source();
    useEffect(() => {
        Axios.get(`https://raw.githubusercontent.com/dwidlee/article/master/articles/${articlePath}/index.json`, {
            cancelToken: source.token
        }).then(({ status, data }) => {
            if (status === 200) {
                console.log(data);
                setArticle(data);
            }
        }).catch(ignored => { });

        return () => source.cancel('');

    }, []);
    return (
        <div>
            {article ? (
                <Container as='a' text>
                    <Header as='h2'>{article.title}</Header>
                    <Divider />
                    {article.tags && article.tags.map((tag, i) => <Label key={i} circular basic size="mini">#{tag}</Label>)}
                    <Divider />
                    <p>
                        {article.summary}
                    </p>
                </Container>
            ) : (
                    <Placeholder>
                        <Placeholder.Header>
                            <Placeholder.Line />
                            <Placeholder.Line />
                            <Placeholder.Line />
                        </Placeholder.Header>
                    </Placeholder>
                )}
        </div>
    );
}




